const i={title:"14.6 TRIPLE INTEGRALS IN CYLINDRICAL AND SPHERICAL COORDINATES",chapterNumber:14,description:"Introduction to evaluating triple integrals using cylindrical and spherical coordinate systems to simplify calculations over specific 3D regions."},e={nodes:[{id:"origin",label:"O",position:[0,0,0],color:"#ff6b6b",size:.2},{id:"xPos",label:"X",position:[2,0,0],color:"#4ecdc4",size:.15},{id:"yPos",label:"Y",position:[0,2,0],color:"#45b7d1",size:.15},{id:"zPos",label:"Z",position:[0,0,2],color:"#ff9f1c",size:.15},{id:"cyl_wedge",label:"Cylindrical Element",position:[1.414,1.414,1.5],color:"#a569bd",size:.12},{id:"sph_wedge",label:"Spherical Element",position:[1.5,1.5,1.5],color:"#f1c40f",size:.12}],edges:[{source:"origin",target:"xPos",label:"x-axis",color:"#4ecdc4",width:.02},{source:"origin",target:"yPos",label:"y-axis",color:"#45b7d1",width:.02},{source:"origin",target:"zPos",label:"z-axis",color:"#ff9f1c",width:.02},{source:"origin",target:"cyl_wedge",label:"r distance",color:"#a569bd",width:.015},{source:"origin",target:"sph_wedge",label:"rho distance",color:"#f1c40f",width:.015}]},o={equations:["\\iiint_G f(r,\\theta,z) dV = \\iiint f(r,\\theta,z) r \\ , dz \\ , dr \\ , d\\theta","x = r \\cos\\theta","y = r \\sin\\theta","z = z","\\Delta V_k = \\rho_k^{*2} \\ sin\\phi_k^* \\Delta\\rho_k \\Delta\\phi_k \\Delta\\theta_k","\\iiint_G f(\\rho,\\theta,\\phi) dV = \\iiint f(\\rho,\\theta,\\phi) \\rho^2 \\ sin\\phi \\, d\\rho \\ , d\\phi \\ , d\\theta","x = \\rho \\sin\\phi \\cos\\theta","y = \\rho \\sin\\phi \\sin\\theta","z = \\rho \\cos\\phi"],aiExplanation:"These formulas explain how to set up triple integrals using non-rectangular coordinate systems. They highlight the necessary extra factors, or Jacobians, required to properly measure volume elements in these spaces: an extra 'r' for cylindrical coordinates, and an extra 'ρ² sin(φ)' for spherical coordinates."},t={metadata:i,graph:e,formulas:o};export{t as default,o as formulas,e as graph,i as metadata};
